"""
MKT Context Commentary — Job chapters 15–18
Run: python3 scripts/zc-context-job-15-18.py

Second dialogue cycle (chs 15–21) begins. Key contextual frames:
- Ch 15: Eliphaz's second speech — primordial-man tradition, divine council motif, fate-of-the-wicked poem
- Ch 16: Job's counter — "miserable comforters," warrior-God imagery, the heavenly witness (ʿēḏ/śāhēḏ)
- Ch 17: Job's despair deepens — suretyship paradox, Sheol as home, corruption as family
- Ch 18: Bildad's second speech — elaborated fate-of-the-wicked poem, firstborn of death, king of terrors
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOB = {
  "15": {
    "1": "<p>Eliphaz opens the second dialogue cycle (chs 15&#8211;21). The first cycle (chs 4&#8211;14) saw the Friends argue from general retribution principles and Job respond with increasingly direct challenges to God. The second cycle shifts: the Friends become more personal and accusatory, and their speeches become less philosophical and more polemical. Eliphaz, who opened the first cycle with gentleness (4:2: &#8220;can we hold back our words?&#8221;), now opens with pointed attack. The cycle structure &#8212; three rounds of speeches with Job responding to each &#8212; is one of the most architecturally sophisticated features of the book.</p>",
    "2": "<p>&#8220;Should a wise man answer with empty words, filling himself with the hot east wind?&#8221; Eliphaz attacks Job&#8217;s wisdom credentials immediately. <em>Rûaḥ qāḏîm</em> (hot east wind) is the desert sirocco &#8212; scorching, desiccating, destructive. In the ancient Near East, the east wind was associated with destruction (Gen 41:6,23 &#8212; the east wind withered the good grain in Pharaoh&#8217;s dream; Ezek 17:10; Hos 13:15). To be &#8220;full of the east wind&#8221; is to be full of hot, damaging, empty talk. Eliphaz is reversing Job&#8217;s wisdom-credentials: Job claimed to have the wisdom the Friends lack (12:3; 13:2); Eliphaz now claims Job speaks hot wind, not wisdom.</p>",
    "3": "<p>&#8220;Should he argue with worthless words, with speeches that accomplish nothing?&#8221; The two criteria Eliphaz applies are <em>ḏāḇār lōʾ-yiskōn</em> (words that profit nothing) and <em>millîm lōʾ-yôʿîl</em> (speeches that do not benefit). These are wisdom-pragmatic criteria: useful speech versus useless speech. In the wisdom tradition, words that do not benefit the hearer and speaker are categorically worthless (Prov 10:19; 15:2; 18:21). Eliphaz is applying the wisdom tradition&#8217;s own criteria against Job&#8217;s complaint-speech. The irony: wisdom speech is being used to silence wisdom-speech.</p>",
    "4": "<p>&#8220;You are actually undermining the fear of God and hindering prayer before him.&#8221; This is Eliphaz&#8217;s most serious theological charge: Job&#8217;s speeches threaten the foundational structures of religion. <em>Yirʾat ʾĕlôah</em> (fear of God) is the book&#8217;s programmatic term &#8212; Job is described as fearing God in 1:1,8,9; 2:3. To undermine the fear of God is to attack the foundation of wisdom (28:28) and covenant-fidelity. <em>Śîaḥ</em> (prayer/meditation) before God &#8212; Eliphaz accuses Job of making prayer itself seem pointless. This charge accurately describes the social danger of Job&#8217;s position even if it misrepresents Job&#8217;s intent.</p>",
    "5": "<p>&#8220;Your mouth reveals your own guilt; you have adopted the tongue of the cunning.&#8221; <em>ʿᵃwōneḵā</em> (your guilt/iniquity) is revealed by the mouth itself &#8212; the speech-as-evidence principle. <em>Lᵉšôn ʿᵃrûmîm</em> (the tongue of the cunning/clever) &#8212; the word <em>ʿārûm</em> is the same used for the serpent in Gen 3:1. By accusing Job of serpentine cleverness, Eliphaz is casting him as a tempter who seduces others away from God. This is the escalation from ch4&#8211;5: there Eliphaz merely suggested Job had some hidden fault; now he accuses Job of actively subverting faith.</p>",
    "6": "<p>&#8220;Your own mouth condemns you, not I; your very lips bear witness against you.&#8221; Eliphaz steps back to appear impartial: he is not the prosecutor but the observer of Job&#8217;s self-incrimination. This is the ancient legal principle that spontaneous speech could be used as evidence (cf. Prov 12:13: &#8220;by the transgression of his lips an evil man is ensnared&#8221;). In Eliphaz&#8217;s framework, Job&#8217;s complaints &#8212; especially his direct challenges to God &#8212; are the evidence of the guilt that originally produced the suffering. The circular logic here is what Job will spend the rest of the dialogue exposing.</p>",
    "7": "<p>&#8220;Are you the first man who was ever born? Were you shaped before the hills?&#8221; Eliphaz invokes the <em>rîʾšôn ʾāḏām</em> (first/primordial man) tradition &#8212; the mythological figure of a pre-existent human who witnessed creation. This figure appears in Ezekiel&#8217;s oracle against the prince of Tyre (Ezek 28:12&#8211;14: &#8220;you were the model of perfection, full of wisdom... you were in Eden, the garden of God&#8221;) and has parallels in Ugaritic texts describing El and Baal as the eldest of the primordial figures. The hills (<em>gᵉḇāʿôṯ</em>) predate human civilization in biblical cosmology (Prov 8:25). To be born before the hills would mean predating creation itself &#8212; wisdom&#8217;s own territory (Prov 8:22&#8211;25).</p>",
    "8": "<p>&#8220;Have you been present in God&#8217;s secret council? Do you think wisdom belongs to you alone?&#8221; The <em>sôḏ</em> (secret council, intimate assembly) of God is a significant concept in OT prophecy. Jeremiah 23:18,22 uses it as the criterion distinguishing true from false prophets: &#8220;who has stood in the council of the LORD?&#8221; Amos 3:7 notes that God reveals his plans to his servants the prophets. The divine council appears in Job&#8217;s prologue (1:6&#8211;12; 2:1&#8211;6) and in 1 Kings 22:19&#8211;23 (Micaiah&#8217;s vision). Eliphaz is mockingly suggesting Job claims council-access &#8212; wisdom as his personal possession. The irony: Job&#8217;s suffering was in fact decided in the divine council, though Job does not know this.</p>",
    "9": "<p>&#8220;What do you know that we do not? What insight have you that we lack?&#8221; The epistemological challenge &#8212; <em>mah-yadaʿtā</em> (what do you know?) &#8212; mirrors Job&#8217;s own challenge in 12:3 (&#8220;I have understanding as well as you; I am not inferior to you&#8221;). Eliphaz turns Job&#8217;s epistemological confidence back against him. In the wisdom tradition, knowledge claims are to be tested against the tradition of the elders (v10), personal experience, and the instruction of the community. Eliphaz is marshaling all three against Job.</p>",
    "10": "<p>&#8220;Among us are both the gray-haired and the very aged, men far older than your father.&#8221; The Friends&#8217; authority claim: tradition mediated through age. In ancient Near Eastern wisdom, <em>śêḇāh</em> (gray hair) and advanced age were marks of authentic wisdom-transmission. The Instruction of Amenemope, the Instructions of Ptahhotep, and Mesopotamian wisdom texts all appeal to the sage&#8217;s great age as credential. Job&#8217;s father is presumably Eliphaz&#8217;s contemporary; by claiming superiority over Job&#8217;s father&#8217;s generation, Eliphaz claims the highest tier of traditional authority. Job will later be vindicated over these very elders (42:7&#8211;9).</p>",
    "11": "<p>&#8220;Are God&#8217;s consolations not enough for you &#8212; the gentle word he has offered you?&#8221; <em>Tanḥûmôṯ ʾēl</em> (consolations of God) &#8212; Eliphaz refers to his own counsel as divine consolation. The claim is extraordinary: the Friends are offering God&#8217;s own comfort through their speeches. <em>Wᵉḏāḇār laʾaṭ ʿimmāḵ</em> (the gentle word with you) &#8212; the Friends&#8217; initial approach was indeed gentle (2:13: seven days of silence). But Job&#8217;s rejection of their comfort has escalated the confrontation. Eliphaz is partly right that the comfort was genuine in intent; what he misses is that it was theologically inadequate to Job&#8217;s actual situation.</p>",
    "12": "<p>&#8220;Why does your heart carry you away? Why do your eyes flare?&#8221; <em>Mah-yiqqāḥᵃḵā libbᵉḵā</em> (what carries away/seduces your heart?) &#8212; the heart as the seat of volition and moral judgment in ANE psychology. When the heart is &#8220;carried away,&#8221; it has lost its grounding in received wisdom and sound judgment. The eye-flash (<em>wᵉmah-yirzemûn ʿênêḵā</em>) may refer to the glittering look of anger or spiritual arrogance &#8212; the outward sign of an inner state that has become unmoored from the tradition. Eliphaz diagnoses Job&#8217;s problem as psychological/spiritual disorientation rather than theological error.</p>",
    "13": "<p>&#8220;That you turn your spirit against God and pour out such words from your mouth?&#8221; <em>Tāšêḇ ʾel-ʾēl rûḥeḵā</em> (you turn your spirit against God) &#8212; the direct accusation of spiritual antagonism toward God. In the wisdom tradition, the spirit (<em>rûaḥ</em>) aligned with God is the source of life and wisdom; a spirit turned against God is dangerous and self-destructive. <em>Wᵉḥôṣēʾṯā mippîḵā millîn</em> (and you bring out such words from your mouth) &#8212; the progression is clear: the turned spirit produces the dangerous words. Eliphaz&#8217;s diagnosis frames Job&#8217;s theological challenge as spiritual rebellion rather than honest protest.</p>",
    "14": "<p>&#8220;What is a mortal man, that he could be clean? Can one born of woman be righteous?&#8221; This verse reprises Eliphaz&#8217;s first-cycle assertion (4:17: &#8220;Can a mortal be more righteous than God? Can even a strong man be more pure than his Maker?&#8221;) but with different framing: not righteousness relative to God but the inherent impurity of being <em>yᵉlûḏ ʾiššāh</em> (born of woman). The phrase &#8220;born of woman&#8221; is a standard idiom for mortal human frailty (Job 14:1; Ps 51:5; Gal 4:4). Eliphaz is arguing from creatureliness: the category &#8220;creature born of woman&#8221; precludes the category &#8220;righteous before God.&#8221;</p>",
    "15": "<p>&#8220;God does not even trust his holy ones; the heavens themselves are not clean in his sight.&#8221; The &#8220;holy ones&#8221; (<em>qᵉḏōšāyw</em>) are the members of the divine council &#8212; the heavenly beings who surround God&#8217;s throne (Job 1:6: &#8220;the sons of God&#8221;; Ps 82:1; Dan 4:13). If even these are not trusted by God, how much less a human? This argument escalates the scale: from the Friend&#8217;s first-cycle point (4:18: even angels are found wanting) to now making the heavens themselves impure. The cosmological scale of divine holiness makes human righteousness-claims look absurd. Qumran community texts later developed this heavenly-purity theology extensively.</p>",
    "16": "<p>&#8220;How much more abominable and vile is man, who laps up wickedness like water!&#8221; The <em>qal wāḥōmer</em> (light-and-heavy) argument from v15: if heavenly beings are not trusted, <em>ʾap kî</em> (how much more) the creature who drinks iniquity like water. <em>Niteʿāḇ wᵉneʾᵃlāḥ</em> (abominable and vile) &#8212; the strongest words for moral corruption, used elsewhere in contexts of idolatry and sexual sin (Deut 24:4; Ps 14:1). Eliphaz&#8217;s rhetoric has intensified enormously from his gentle opening in 4:2&#8211;6. The second cycle reveals how the Friends&#8217; theodicy, under pressure, moves toward denunciation.</p>",
    "17": "<p>&#8220;I will show you &#8212; listen to me.&#8221; The instruction formula (<em>šimʿāh-lî</em>, listen to me) transitions Eliphaz from accusation to teaching. What follows (vv18&#8211;35) is the fate-of-the-wicked poem that occupies the bulk of ch15. By prefacing it with personal testimony (&#8220;what I have seen&#8221;) and traditional authority (&#8220;what wise men have declared,&#8221; v18), Eliphaz frames his description of the wicked as both empirically and traditionally validated. The implicit application to Job makes this the most extensive indirect accusation in the book.</p>",
    "18": "<p>&#8220;What wise men have declared, passed down from their fathers without concealment.&#8221; The appeal to unbroken tradition (<em>miʾᵃḇôṯām lōʾ-kiḥēḏû</em>, from their fathers without concealment) is the classic wisdom-authority claim: accumulated experiential knowledge, faithfully transmitted across generations. This contrasts with Job&#8217;s implied claim to direct insight that overrides tradition. The wisdom literature of Egypt and Mesopotamia similarly invokes the chain of transmission: Ptahhotep opens with the wisdom of ancestors; Amenemope addresses his son as recipient of the tradition. Eliphaz positions himself within this authoritative stream and Job outside it.</p>",
    "19": "<p>&#8220;To those whose land was their own alone, before foreigners came among them.&#8221; This parenthesis may assert the purity of the tradition: it originated in a land uncorrupted by foreign influence. Some interpreters see it as a reference to pre-Israelite patriarchal tradition &#8212; the Edomite wisdom tradition, given that Eliphaz is a Temanite from Edom, a region renowned for wisdom (Jer 49:7; Obad 8). The tradition Eliphaz claims is ethnic and territorial, not merely professional. This grounds his authority claim in deep indigenous wisdom rather than mere learned craft.</p>",
    "20": "<p>&#8220;The wicked man twists in anguish all his days; the years allotted to the tyrant are numbered.&#8221; The fate-of-the-wicked poem begins. <em>Mithôlēl</em> (twisting in anguish, writhing) describes persistent torment &#8212; not a sudden catastrophe but a lifelong condition of inner suffering. <em>ʿārîṣ</em> (tyrant, ruthless man) &#8212; the word used for oppressors and violent rulers throughout the prophets (Isa 13:11; 25:3&#8211;5; Ps 37:35). Eliphaz&#8217;s portrait begins with existential anguish: the wicked man is not at peace even in apparent prosperity. This is psychologically astute even if theologically misapplied to Job.</p>",
    "21": "<p>&#8220;A sound of terror is always in his ears; in his moments of peace the destroyer strikes him.&#8221; <em>Qôl-pᵉḥāḏîm bᵉʾoznāyw</em> (a sound of terrors in his ears) &#8212; perpetual anxiety as the inner life of the wicked. <em>Bišlômāh</em> (in his peace/security) the destroyer comes &#8212; the word <em>šālôm</em> (peace, wholeness) normally denotes the condition of the righteous; for the wicked, even apparent peace contains the seed of terror. <em>Šōḏēḏ</em> (destroyer) &#8212; a term used for the divine agent of destruction (Jer 48:8; 51:56). The wicked man can never enjoy the peace that is the righteous man&#8217;s inheritance.</p>",
    "22": "<p>&#8220;He has no hope of escaping from the darkness; he is marked for the sword.&#8221; <em>Lōʾ-yaʾᵃmên šûḇ</em> (he does not trust/believe he can return) from the darkness &#8212; a permanent condition of hopelessness. The darkness that envelopes Job (10:21&#8211;22) is here attributed to the wicked. This is the first point of contact between Eliphaz&#8217;s description of the wicked and Job&#8217;s description of his own condition &#8212; a contact that makes the implicit application to Job increasingly clear as the poem develops. <em>Ṣāpûn hûʾ liḥāreḇ</em> (he is appointed for the sword) &#8212; his fate is sealed.</p>",
    "23": "<p>&#8220;He wanders in search of food, crying, &#8216;Where is it?&#8217; He knows the day of darkness is ready and near.&#8221; The wandering hunger of the wicked contrasts with the settled prosperity of the righteous. <em>Nāḏeḏ hûʾ lāleḥem ʾayyēh</em> (he wanders for bread &#8212; where?) &#8212; the exile-and-hunger motif that in the prophets marks divine judgment (Lam 1:11; 4:9). The awareness of impending darkness is the psychological torment: not only does the day of darkness come, but the wicked person knows it is near. This consciousness of doom-without-escape is the distinctive signature of Eliphaz&#8217;s wicked man.</p>",
    "24": "<p>&#8220;Distress and anguish terrorize him; they overpower him like a king advancing to battle.&#8221; <em>Ṣar ûmᵉṣûqāh</em> (distress and anguish) &#8212; the classic paired terms of covenant curse (Deut 28:53,55,57; Isa 8:22; Zeph 1:15). The simile &#8220;like a king advancing to battle&#8221; (<em>kᵉmelek ʿāṯîḏ lᵉkîḏôr</em>) &#8212; the wicked person&#8217;s internal suffering overwhelms him like an invading army. This is the ancient Near Eastern war-metaphor for psychological/spiritual crisis. The comparison inverts normal power: the &#8220;great man&#8221; (by worldly measures) is overwhelmed by forces he cannot fight.</p>",
    "25": "<p>&#8220;For he has stretched out his hand against God and defied the Almighty.&#8221; The explicit sin of the wicked man: hand-stretching against God (<em>nāṭāh ʿal-ʾēl yāḏô</em>) and defiance (<em>ʾel-šaddai yitgabbār</em>). This is Eliphaz&#8217;s implicit charge against Job: Job&#8217;s speeches constitute exactly this &#8212; stretching the hand against God, acting with defiance against the Almighty. The escalation from the first-cycle speech (4:7&#8211;8) is evident: then Eliphaz hinted; now he charges. The rhetoric of the wicked man is designed to describe Job without naming him.</p>",
    "26": "<p>&#8220;Charging at him neck-forward, pressing against the thick boss of his shield.&#8221; The combat imagery intensifies: the wicked man charges God like a warrior (<em>yārûṣ ʾēlāyw bᵉṣawwārô</em>, charging at him neck-forward). <em>Bᵉgaḇ bᵉginnôṯ māginnāyw</em> (pressing against the thick bosses of his shields) &#8212; the bosses are the raised metal knobs on a warrior&#8217;s shield, the most armored part. Attacking the most armored part of God&#8217;s defense is the height of futile arrogance. The image participates in the OT warrior-God tradition (Exod 15; Hab 3; Ps 24:8) but here inverted: God is the defender against the wicked aggressor.</p>",
    "27": "<p>&#8220;He has become fat-faced, his sides padded with flesh.&#8221; The transition from warrior imagery to prosperity imagery: the wicked man is physically fat (<em>kāśāh pānāyw bᵉḥêlpāyw</em>, covered his face with his flesh) and wealthy-looking. In the ancient world, physical corpulence was a sign of prosperity (Ps 17:10; 73:4&#8211;7; Jer 5:28). The wicked man&#8217;s outward flourishing is the context for the destruction that follows: he looks prosperous, but he is building on a foundation that will collapse. This is the paradox of Psalm 73 and Proverbs 1&#8211;9 &#8212; the temporary prosperity of the wicked.</p>",
    "28": "<p>&#8220;He makes his home in ruined cities, in houses no one else inhabits.&#8221; The dwelling-in-ruins detail is striking: despite apparent prosperity (v27), the wicked man inhabits condemned places. This may reflect a judgment-tradition: the wicked are those who take possession of places under divine curse (compare the destruction of Sodom &#8212; Gen 19:24&#8211;25 &#8212; and prophetic descriptions of ruined cities as signs of divine judgment: Isa 13:20&#8211;22; Jer 50:39&#8211;40). The wicked man&#8217;s home is already under curse even when he occupies it; his prosperity is built on condemned ground.</p>",
    "29": "<p>&#8220;He will not remain wealthy; his substance will not last.&#8221; The prediction of reversal: current prosperity will not endure. <em>Lōʾ-yeʿᵃšer</em> (he will not be wealthy), <em>lōʾ-yāqûm ḥêlô</em> (his wealth will not endure). This is the foundational claim of the two-ways theology: eventual reversal of apparent prosperity. The wisdom literature consistently argues this case (Ps 37:1&#8211;2,9&#8211;10; 49:16&#8211;20; Prov 11:28). Eliphaz is applying to the wicked in general what he implies Job&#8217;s future will be if Job continues on his current path.</p>",
    "30": "<p>&#8220;He will not escape from the darkness; flame will wither his branches, and by the breath of God&#8217;s mouth he will be swept away.&#8221; <em>Lōʾ-yāsûr miṇ-ḥōšeḵ</em> (he will not turn from the darkness) &#8212; the darkness is permanent entrapment. <em>Yibaššēš šalhaḇeṯ nîṣṣô</em> (flame will wither his blossom/branch) &#8212; the tree imagery for human life: the wicked man&#8217;s flourishing branch is scorched. <em>Wᵉyāsur bᵉrûaḥ pîhû</em> (and he will be removed by the breath of God&#8217;s mouth) &#8212; the divine breath that gives life (33:4) here removes the wicked man like wind blows away chaff (Ps 1:4; Isa 17:13). Creation-breath becomes judgment-breath.</p>",
    "31": "<p>&#8220;Let him not deceive himself by trusting in what is empty, for emptiness will be his only return.&#8221; <em>Šāwᵉ</em> (emptiness, vanity, falsehood) as both the foundation the wicked trusts and the reward they receive &#8212; the boomerang principle of Proverbs (Prov 1:18: &#8220;they lie in wait for their own blood&#8221;). The verse may be a warning-instruction or a description: either &#8220;let him not deceive himself&#8221; (hortatory) or &#8220;he deceives himself&#8221; (descriptive). The ambiguity is itself meaningful: both the warning and its violation are present simultaneously in the wicked man&#8217;s situation.</p>",
    "32": "<p>&#8220;It will be completed before his time; his branch will not stay green.&#8221; <em>Bᵉlōʾ-yômô</em> (before his day/time) &#8212; premature death as divine judgment. The green branch (<em>kappô ṯirʾᵃneh</em>) that fails to remain green is the tree-of-life image inverted: instead of the righteous man&#8217;s flourishing (Ps 1:3; Prov 11:28: &#8220;the righteous will flourish like a green leaf&#8221;), the wicked man&#8217;s branch withers prematurely. The temporal element (before his time) responds to the problem of delayed justice that Job has raised: the wicked&#8217;s prosperity is always temporary even when it appears enduring.</p>",
    "33": "<p>&#8220;He will shed his unripe grapes like the vine, and drop his blossoms like the olive tree.&#8221; The agricultural metaphors: fruit production that fails before maturity. <em>Yāḥmōs kāggepen bišrô</em> (he will violently strip off his unripe grapes) &#8212; the <em>ḥāmas</em> (violence, stripping) is done to his own fruit; his violence destroys his own productivity. The olive blossom (<em>nēṣeṯ zāyiṯ</em>) that drops before bearing fruit is a standard image of failed potential (Deut 28:40). The wicked man&#8217;s descendants and projects are the &#8220;fruit&#8221; that never matures &#8212; a generational curse.</p>",
    "34": "<p>&#8220;For the assembly of the godless will be desolate, and fire will consume the tents of corruption.&#8221; <em>ʿᵃḏaṯ ḥānēp</em> (assembly of the godless/profane) &#8212; the community rather than just the individual. The fate-of-the-wicked judgment extends to the social group: the whole assembly will be desolate (<em>galmûḏ</em>, barren/desolate). <em>Bribĕ šōḥaḏ</em> (tents of bribery/corruption) &#8212; in the ANE, bribery and corruption were the emblematic sins of unjust rulers and judges. Fire as divine judgment on corrupt settlements recalls the fate of Sodom and Gomorrah (Gen 19:24) and the prophetic judgment oracles (Amos 1&#8211;2).</p>",
    "35": "<p>&#8220;They conceive trouble and give birth to evil; their inmost being produces only deceit.&#8221; The reproductive metaphor for wickedness &#8212; <em>hārāh ʿāmāl wᵉyāled ʾāwen</em> (conceiving trouble and giving birth to iniquity) &#8212; recalls Ps 7:14 (&#8220;he who conceives trouble and gives birth to lies&#8221;) and Isa 59:4 (&#8220;they conceive trouble and give birth to evil&#8221;). The <em>ḥarsô</em> (their inner part/belly) that produces <em>mirmāh</em> (deceit) closes the poem with an inwardness claim: the wicked person&#8217;s core is generative of nothing but deception. The poem&#8217;s structural movement &#8212; from existential anguish (v20) to explicit rebellion (v25) to physical destruction (vv30&#8211;34) to moral inwardness (v35) &#8212; is deliberately comprehensive.</p>"
  },
  "16": {
    "1": "<p>Job responds to Eliphaz&#8217;s second speech. The dialogic pattern of the book is at its most intense in the second cycle: the Friends attack more personally; Job&#8217;s responses become more anguished and more direct in their address to God. Chapter 16 is often considered one of the high points of the book&#8217;s poetry &#8212; the complaint against God as warrior (vv9&#8211;14) and the appeal to the heavenly witness (vv18&#8211;21) both appear here. The speech is also structured around the contrast between the Friends&#8217; false comfort and the genuine witness Job seeks in heaven.</p>",
    "2": "<p>&#8220;I have heard all this before. You are miserable comforters, every one of you.&#8221; <em>Mᵉnaḥămê ʿāmāl</em> (comforters of trouble/toil) &#8212; the bitter reversal of the Friends&#8217; stated purpose. They came to &#8220;comfort&#8221; (<em>lᵉnaḥamô</em>, 2:11) but have produced <em>ʿāmāl</em> (toil, grief, trouble). The term <em>ʿāmāl</em> encompasses both the labor of suffering and the grief it produces &#8212; the Friends have intensified Job&#8217;s suffering rather than relieving it. This is the paradigmatic indictment of theological counsel that prioritizes systematic correctness over genuine compassion with the sufferer.</p>",
    "3": "<p>&#8220;Will these empty words never stop? What gives you the confidence to keep answering me?&#8221; <em>Diḇrê-rûaḥ</em> (words of wind/breath) &#8212; the same accusation Eliphaz made against Job (15:2: hot east wind) is turned back on the Friends. <em>Mah-yamrîṣᵉḵā kî taʿᵃneh</em> (what provokes/emboldens you to keep answering?) &#8212; the verb <em>mārēṣ</em> (to strengthen, provoke, make bold) suggests that something external is driving the Friends&#8217; persistence. Job cannot understand why they continue when their words provide no relief. The exhaustion of unproductive theological debate is palpable.</p>",
    "4": "<p>&#8220;I could talk just like you if you were in my place &#8212; I could pile words against you and shake my head at you.&#8221; Job performs the perspectival reversal that the Friends have systematically refused to do. <em>Lûle ʾᵃnî kᵉnafšᵉḵem</em> (if I were in your place) &#8212; the empathy exercise the Friends did for seven days (2:13) but abandoned when they began to speak. The head-shaking (<em>ʾānîṭāh ʿᵃlêḵem bᵉrōʾšî</em>) is the gesture of contemptuous pity (Ps 22:7; Jer 18:16; Lam 2:15) &#8212; the same gesture Job endures. He is imagining delivering to them what they are delivering to him.</p>",
    "5": "<p>&#8220;I would strengthen you with my words, and the comfort of my lips would ease your grief.&#8221; The counterfactual comfort Job would offer &#8212; genuine strengthening (<em>ʾᵃḥazzēq bᵉḵem bᵉmî pî</em>) rather than accusation. The verse is both accusatory (the Friends&#8217; comfort fails this standard) and self-revelatory (Job understands what genuine comfort looks like). The comfort of the lips (<em>nîḏ śᵉpāṯay yaḥśôḵ</em>) that restrains grief is the wisdom literature&#8217;s ideal of therapeutic speech (Prov 15:4; 12:25). Job has internalized the wisdom ideal; the Friends have violated it.</p>",
    "6": "<p>&#8220;If I speak, the pain is not relieved; and if I stay silent, how much of it leaves me?&#8221; The double bind of unrelievable suffering: speech brings no relief (<em>lōʾ-yeḥaś kᵉʾēḇî</em>), but silence relieves none of it either (<em>mah-minnî yaʿᵃḇōr</em>). This existential paralysis &#8212; no action available that would improve the situation &#8212; is what distinguishes Job&#8217;s suffering from ordinary trial. It is also the theological problem at the center of the book: if there is no action Job can take that would change his situation, then either his suffering is beyond human remedy (which it is) or God must act directly (which Job demands).</p>",
    "7": "<p>&#8220;But now he has utterly exhausted me; he has made desolate everyone around me.&#8221; Job shifts from the Friends to God as the source of his desolation. <em>ʿAttāh hilʾāh</em> (now he has exhausted/made weary) &#8212; <em>lāʾāh</em> means to be worn out, exhausted to the point of breakdown. The desolation of Job&#8217;s community (<em>kol-ʿāḏāṯî</em>) &#8212; everyone around him is also affected. Job&#8217;s suffering is not merely individual; it has shattered his social world. Compare 19:13&#8211;19 where Job catalogs the social alienation in detail. The corporate dimension of the suffering is part of what makes it appear like divine curse rather than mere tragedy.</p>",
    "8": "<p>&#8220;You have wasted my flesh until it shows &#8212; that itself is a witness; my emaciation rises up and testifies against me to my face.&#8221; Job&#8217;s body has become evidence &#8212; but evidence of the opposite of what the Friends claim. They argue his body-as-ruin proves his guilt; Job says his body-as-ruin is the witness to his unjust treatment. <em>Wᵉtiqmᵉṭēnî lᵉʿēḏ</em> (it has become a witness against me) &#8212; the physical wreckage of Job&#8217;s body testifies, but to what? The ambiguity is deliberate: the same visible evidence supports opposite verdicts depending on the interpretive framework. Job&#8217;s framework reads the suffering as testimony against God&#8217;s justice; the Friends&#8217; framework reads it as testimony against Job&#8217;s righteousness.</p>",
    "9": "<p>&#8220;He has torn me apart in his wrath and pursued me; he gnashes his teeth at me; my enemy fixes his sharpened gaze upon me.&#8221; The divine-warrior attack imagery begins in earnest. <em>ʾAppô ṭārap wayiśṭᵉmēnî</em> (in his anger he has torn and hated/pursued me) &#8212; <em>ṭārap</em> is the verb used for predatory animals tearing prey (Gen 37:33; 44:28; Hos 6:1). The teeth-gnashing (<em>yiḥᵃrōq ʿālay bᵉšinnāyw</em>) and the enemy-gaze (<em>ṣārî yilṭôš ʿênāyw lî</em>) are the gestures of predator toward prey. Job has reversed the creation-order: instead of the divine Creator caring for the creature, the divine Warrior hunts it. This language of God-as-predator is the most extreme form of the book&#8217;s theodicy-challenge and has direct parallels in Lamentations 3:1&#8211;18.</p>",
    "10": "<p>&#8220;They open their mouths wide at me; they strike my cheek in contempt; they have gathered themselves together against me.&#8221; The human mockers join the divine assault: <em>pāʿᵃrû ʿālay bᵉpîhem</em> (they gape at me with their mouths) &#8212; the gesture of contemptuous mockery (Ps 22:13; Lam 2:16; 3:46). The cheek-strike (<em>lᵉḥît yakkûnî bᵉḥerpāh</em>) is a gesture of profound humiliation in the ancient Near East (1 Kgs 22:24; Mic 5:1; Isa 50:6). The convergence of divine assault (v9) and human humiliation (v10) creates the double abandonment &#8212; by God and by human community simultaneously &#8212; that will culminate in 19:13&#8211;22.</p>",
    "11": "<p>&#8220;God has surrendered me to the evildoers and thrown me into the hands of the wicked.&#8221; <em>Yasgîrēnî ʾēl ʾel-ʿᵃwîl</em> (God has shut me up/surrendered me to the ungodly) &#8212; <em>sāgar</em> (to shut up, deliver up) is the legal term for extradition or surrender to an enemy (Deut 32:30; 1 Sam 23:11; Ps 31:9). God is the agent who has delivered Job to his enemies rather than protecting him from them. This is the paradox of the prologue reversed from below: the reader knows God permitted Satan to afflict Job; Job experiences it as God handing him over to the wicked. Both perspectives are simultaneously true, which is part of the book&#8217;s theological depth.</p>",
    "12": "<p>&#8220;I was living in ease, and he shattered me; he grabbed me by the neck and broke me apart; he stood me up as his target.&#8221; <em>Šālēw hāyîtî wayyᵉparpᵉrēnî</em> (I was at ease and he shattered me) &#8212; <em>šālēw</em> (quiet, at rest, at ease) is Job&#8217;s pre-disaster condition; <em>pārpar</em> (to shake apart, shatter) is its violent reversal. The neck-seizure (<em>wayyōʾḥᵃzēnî bᵉʿōrep</em>) and being set up as target (<em>wayyᵉśîmēnî lô lᵉmatarrāh</em>) &#8212; <em>matarrāh</em> (target) appears only here and in Lam 3:12 (&#8220;he bent his bow and set me as a target for his arrow&#8221;). Lamentations draws on Job&#8217;s vocabulary, suggesting that the exilic community&#8217;s suffering was interpreted through the Job-template.</p>",
    "13": "<p>&#8220;His archers surround me; he slashes into my kidneys without mercy and spills my gall on the ground.&#8221; <em>Rabbāyw yibbāqᵃʿû kᵉlāyōṯāy</em> (his archers/arrows break through my kidneys) &#8212; the kidneys (<em>kᵉlāyôṯ</em>) in ancient Near Eastern anatomy were the seat of conscience and deepest self (Ps 7:10; 16:7; Jer 11:20; 17:10). To pierce the kidneys is to penetrate to the innermost person. <em>Yišpōḵ lāʾāreṣ mᵉrērāṯî</em> (he pours out my gall on the ground) &#8212; the gall bladder spilling is a clinical description of catastrophic internal injury. The combination of military imagery (archers, breaching) and anatomical detail produces an image of total devastation of the interior life.</p>",
    "14": "<p>&#8220;He breaks through me, breach after breach; he charges at me like a great warrior.&#8221; <em>Yiprᵉṣēnî pereṣ ʿal-pᵉnê-pāreṣ</em> (he breaks through me, breach upon breach) &#8212; the <em>pāreṣ</em> (breach) imagery from siege warfare: a wall breached multiple times cannot be repaired. <em>Yārûṣ ʿālay kᵉgibbôr</em> (he charges at me like a warrior) &#8212; the <em>gibbôr</em> (mighty man, hero) was the elite warrior of ancient armies. God assaulting Job like a siege-engineer breaching walls and a soldier charging is the culmination of the warrior imagery in vv9&#8211;14. The passage as a whole is one of the most powerful descriptions of divine assault in the OT and is echoed structurally by Lamentations 3.</p>",
    "15": "<p>&#8220;I have sewn sackcloth over my skin and pressed my dignity down into the dust.&#8221; Job&#8217;s outward mourning-posture matches his inward devastation. <em>Tāpārtî śaq ʿᵃlê giltî</em> (I sewed sackcloth over my skin) &#8212; sackcloth (<em>śaq</em>) was the standard garment of mourning, grief, and petition (Gen 37:34; Joel 1:8,13; Jonah 3:6&#8211;8). <em>Wᵉʿôlaltî bāʿāpār qarnî</em> (and I have thrust my horn into the dust) &#8212; the horn (<em>qeren</em>) was the symbol of dignity, strength, and honor in the ancient world (1 Sam 2:1,10; Ps 75:4&#8211;5; 92:10; 148:14). Pressing the horn into the dust is the act of complete self-abasement, the reversal of honored status.</p>",
    "16": "<p>&#8220;My face is flushed raw from weeping, and the shadow of death rests on my eyelids.&#8221; <em>Pānay ḥᵃmarmarāh minnî-ḇeḵî</em> (my face is red/inflamed from weeping) &#8212; the physical marks of prolonged grief. <em>Ṣalmāweṯ ʿal-ʿappappāy</em> (shadow of death on my eyelids) &#8212; <em>ṣalmāweṯ</em> appears again, now not as the place of death but as a presence settled on Job&#8217;s face. The eyelids as the location of <em>ṣalmāweṯ</em> is striking: the organ of sight is covered by death-shadow. Job&#8217;s vision is clouded by proximity to death. Despite this, v17 immediately states his innocence &#8212; the external marks of death-sentence do not correspond to interior guilt.</p>",
    "17": "<p>&#8220;Yet no violence has been done by my hands, and my prayer has been pure.&#8221; The contrastive <em>ʿal lōʾ-ḥāmās bᵉkappāy</em> (yet no violence in my palms) &#8212; the palms as the locus of moral action in the ancient world. <em>Ḥāmās</em> (violence, wrong) is one of the strongest terms for unjust oppression in the OT (Gen 6:11; Ezek 28:16; Hab 1:2&#8211;3). <em>ûṣᵉlāṯî zakāh</em> (and my prayer has been pure/clear) &#8212; the purity of prayer reflects the purity of moral standing. This verse is the hinge between the warrior-assault passage (vv9&#8211;16) and the witness-appeal (vv18&#8211;21): the suffering described in vv9&#8211;16 is unjust precisely because of the innocence stated in v17.</p>",
    "18": "<p>&#8220;O earth, do not cover my blood; let my cry find no place to settle!&#8221; The appeal to the earth as witness-for-the-prosecution is grounded in the Abel tradition: Abel&#8217;s blood cried out from the ground where it was covered (Gen 4:10&#8211;11). Uncovered blood in the ancient world was a legal problem: it demanded justice and could not rest until satisfied (Num 35:33; Isa 26:21; Ezek 24:7&#8211;8). By appealing for his blood to remain uncovered (<em>ʾal-tᵉḵasî dāmî ʾāreṣ</em>), Job is inviting the earth itself to carry his cry for justice upward until it is answered. The earth-as-witness sets up the heaven-as-witness in v19.</p>",
    "19": "<p>&#8220;Even now my witness is in heaven, and my advocate is on high.&#8221; <em>ʿēḏî baššāmayim</em> (my witness in the heavens) and <em>śāhᵃḏî bammᵉrômîm</em> (my testifier on high) &#8212; this is the most significant intercessor-passage in the second cycle. Who is this heavenly witness? Interpretive options: (1) God himself &#8212; a split between God the antagonist (vv9&#8211;14) and God the advocate; (2) an angelic figure in the divine council parallel to the <em>meliṣ</em> of 33:23; (3) Job&#8217;s own righteousness personified as a heavenly witness. The most natural reading in context is that Job is appealing to God against God &#8212; a desperate appeal to God&#8217;s own integrity to vindicate what God&#8217;s actions seem to deny. This will reach its climax in 19:25&#8211;27 (the <em>gōʾēl</em>).</p>",
    "20": "<p>&#8220;My friends scorn me, yet my eye pours out tears to God.&#8221; The social abandonment &#8212; friends who mock (<em>mᵉlîṣay rēʿāy</em>, my intercessors/friends are my scorners) &#8212; against the persistent upward orientation of weeping to God. <em>ʾEl-ʾĕlôah</em> (to God) &#8212; the tears are directional; they go not downward into the earth but upward toward God. The paradox: God is both the cause of the suffering (vv9&#8211;14) and the address of the tears (v20). This is not contradiction but the structure of biblical lament: the complaint is directed to the very One who is accused, because there is no other court of appeal.</p>",
    "21": "<p>&#8220;If only a mortal man could plead with God the way a man pleads for his neighbor.&#8221; The <em>môkîaḥ</em>-longing from 9:33 returns in different form: <em>wᵉyôkîaḥ lᵉgeḇer ʿim-ʾĕlôah ûḇen-ʾāḏām lᵉrêʿēhû</em> (if a man could argue with God as a man argues for his neighbor). The legal advocacy image (<em>yākaḥ</em>, to argue/contend in legal setting) applied to the impossible case: a human being pleading another human&#8217;s case before God. Job longs for this structure to exist between humanity and God. The NT answer is the incarnate High Priest who was in every way like his brothers (Heb 2:17&#8211;18; 4:15&#8211;16): one who can plead humanity&#8217;s case from within the human condition.</p>",
    "22": "<p>&#8220;For the few years left are slipping past, and I am walking a road from which there is no return.&#8221; <em>Šᵉnôṯ mispar yᵉʾĕṯāyû</em> (the years of number/few years will come) &#8212; Job&#8217;s awareness that time is running out for the vindication he seeks. <em>Wᵉʾōraḥ lōʾ-ʾāšûḇ ʾehlōḵ</em> (and I am walking a path of no return) &#8212; the one-way road to death makes the urgency of justice acute. If vindication does not come before death, it will not come at all &#8212; unless there is something beyond death (ch19 will explore this). The speech ends with the one-way road, preparing for ch17&#8217;s meditation on Sheol as the only destination.</p>"
  },
  "17": {
    "1": "<p>Job continues his response (ch17 may be part of a single speech begun in ch16, divided by modern chapter divisions). <em>Rûḥî ḥubbālāh</em> (my spirit is ruined/exhausted) &#8212; <em>ḥābal</em> means to bind, pledge, or destroy; here it suggests the spirit has been handed over to destruction. <em>Yamay nizᵃʿākû</em> (my days are extinguished) &#8212; the lamp-imagery for life (cf. 18:5&#8211;6): Job&#8217;s days are being put out like a lamp. <em>Qᵉḇārîm lî</em> (the grave for me) &#8212; the plural may indicate multiple graves awaiting, or is an intensified form. Death has become Job&#8217;s horizon.</p>",
    "2": "<p>&#8220;Surely there are mockers all around me, and my eye rests on their hostile provocation.&#8221; <em>Hᵃtullîm</em> (mockers) surround Job; their mockery is not background noise but foreground torment. <em>Wᵉḇᵉmirāhôṯam tālān ʿênî</em> (my eye rests on their provocation) &#8212; the eye that was pouring out tears to God (16:20) now rests on human hostility. This contrast between vertical lament (toward God) and horizontal hostility (from people) structures much of Job&#8217;s situation. The same tension appears in Psalm 88 &#8212; the most hopeless of the psalms &#8212; where the sufferer&#8217;s companions become darkness itself.</p>",
    "3": "<p>&#8220;Give me a pledge yourself; who else is there to strike hands with me?&#8221; <em>Śîmāh-nāʾ ʿārᵉḇēnî ʿimmāḵ</em> (place a pledge-surety with yourself for me) &#8212; the legal concept of <em>ʿēreḇ</em> (surety, pledge). In ancient Near Eastern commerce and law, a surety was a third party who guaranteed another&#8217;s debt or obligation (Gen 43:9: Judah as surety for Benjamin; Prov 6:1&#8211;5; 11:15; 17:18). Job asks God to become his own guarantee &#8212; a logical paradox: God pledges to God for Job. The striking-of-hands (<em>mî hûʾ lî yitqāʿ</em>, who will shake hands for me?) was the gesture sealing a surety agreement. Hebrews 7:22 interprets Christ&#8217;s priesthood in exactly these terms: &#8220;Jesus has become the guarantee of a better covenant.&#8221;</p>",
    "4": "<p>&#8220;For you have closed off their minds from true understanding; therefore you will not let them triumph.&#8221; <em>Libbām ṣāpantā mibināh</em> (their heart you have hidden from understanding) &#8212; God has concealed understanding from the Friends, which is why they cannot help Job. This is a striking theological claim: the Friends&#8217; inadequacy is not merely intellectual failure but divine action. Their hearts are closed to the understanding that would allow them to serve as genuine advocates. <em>ʿal-kēn lōʾ tᵉrōmēm</em> (therefore you will not let them triumph/be exalted) &#8212; the Friends&#8217; inability to vindicate themselves before God is connected to their inability to understand Job&#8217;s situation. Divine hardening serves the book&#8217;s design: no human wisdom can solve Job&#8217;s problem; only God can.</p>",
    "5": "<p>&#8220;He who betrays his friends for personal gain &#8212; his children&#8217;s eyes will fail.&#8221; This proverbial statement is applied to the Friends: they have betrayed Job (who is their <em>rēaʿ</em>, friend/companion) by choosing comfortable theology over genuine solidarity. <em>Lᵉḥēleq</em> (for a share/portion) &#8212; they have a stake in maintaining the retributive system because they benefit from a world where righteousness guarantees prosperity. Their children&#8217;s failing eyes (<em>wᵉʿênê bānāyw tiklenāh</em>) is the curse-formula: the sin of the fathers visits the third and fourth generation (Exod 20:5). The Friends&#8217; theological betrayal of Job is functionally equivalent to betraying a friend for personal gain.</p>",
    "6": "<p>&#8220;He has turned me into a proverb among the nations &#8212; I am one before whose face men spit.&#8221; <em>Wᵉhiṣṣîḡanî limšōl ʿammîm</em> (he has set me up as a proverb/byword of the peoples) &#8212; being made a <em>māšāl</em> (proverb, taunt-song, byword) is a standard formula of covenant curse in the OT (Deut 28:37; 1 Kgs 9:7; Jer 24:9; Ezek 14:8; Ps 44:15). To become a byword is to become the negative example by which others measure their own fortunate condition. The face-spitting (<em>tōpeṯ-pānîm ʾehyeh</em>) is the extreme humiliation gesture (Num 12:14; Deut 25:9; Isa 50:6). Job has descended from honored elder (29:7&#8211;25) to social outcast.</p>",
    "7": "<p>&#8220;My eye has grown dim from sorrow, and all my limbs are like shadows.&#8221; <em>Wattikah mikkāʿas ʿênî</em> (my eye has grown dim/exhausted from vexation) &#8212; the eye that weeps (16:20), that rests on mockery (17:2), now fails from grief. <em>Yᵉṣārāy kāṣṣēl kullām</em> (my limbs are all like a shadow) &#8212; the bodily dissolution that began with flesh-wasting (16:8) reaches the entire body. In the ancient world, the shadow (<em>ṣēl</em>) was associated with both the insubstantial (Ps 39:6: &#8220;man is a mere shadow&#8221;; Eccl 6:12) and with protection (Ps 17:8; 91:1). Job has become the shadow without protection &#8212; insubstantial, about to disappear.</p>",
    "8": "<p>&#8220;Upright men are horrified by this; the innocent rises up against the godless.&#8221; A seemingly intrusive verse: the upright men&#8217;s horror may be at the injustice of Job&#8217;s treatment, or at Job&#8217;s apparent descent into impiety. The verse may be Job&#8217;s self-location within the community of the righteous: even if the Friends reject him, the <em>yᵉšārîm</em> (upright) and <em>nāqî</em> (innocent) can recognize the injustice. <em>Wᵉṯāqōm ʿal-ḥānēp ḥônēn</em> (the innocent rises against the godless) &#8212; Job positioning himself as the innocent who stands against the godless accusers, however the Friends have positioned themselves.</p>",
    "9": "<p>&#8220;The righteous man keeps to his course, and the one with clean hands grows stronger and stronger.&#8221; Despite everything, Job affirms the path of the righteous: <em>wᵉyōsēp ṣaddîq darkô</em> (the righteous man adds to/continues his way) and <em>ûṭᵉhar-yāḏayim yōsîp ʾōmeṣ</em> (the one with clean hands grows stronger). This is an affirmation of moral persistence against circumstantial assault &#8212; the righteous do not abandon their course because suffering contradicts their expectation. The verse anticipates the resolution of ch31, where Job maintains his integrity claim to the end, and stands in tension with the despair of vv1&#8211;7 and 11&#8211;16 within the same speech.</p>",
    "10": "<p>&#8220;But come, all of you, try again &#8212; I still cannot find a wise man among you.&#8221; The challenge to renewed debate: <em>ûlām kullām tāšuḇû-nāʾ</em> (but all of you, please return/try again). Despite the impossibility (&#8220;I still cannot find a wise man among you&#8221;), Job is not finished. This is the most direct assessment of the Friends&#8217; failure: despite their appeals to tradition, age, and experience, none of them qualifies as a genuine <em>ḥāḵām</em> (wise man) in Job&#8217;s assessment. The wisdom tradition&#8217;s highest credential &#8212; being truly wise &#8212; is denied to its self-appointed representatives.</p>",
    "11": "<p>&#8220;My days are over; my plans have been cut off &#8212; even the secret longings of my heart.&#8221; <em>Yāmay ʿāḇᵃrû zimōṯay</em> (my days have passed, my purposes/plans) &#8212; <em>zimmāh</em> (plan, purpose, thought) here has the positive sense of life-plans and designs, not its common negative sense (wickedness). The cutting off of the heart&#8217;s possessions (<em>môrāšê lᵉḇāḇî</em>, the possessions of my heart) &#8212; the private longings that never became public &#8212; represents the most intimate loss: not just status and family but the unlived hopes that sustained his interior life.</p>",
    "12": "<p>&#8220;They make night into day; they say, &#8216;The light is near,&#8217; even while darkness surrounds them.&#8221; The Friends&#8217; false comfort: <em>laylāh lᵉyôm yāśîmû</em> (they set night as day) &#8212; inverting the order of reality to offer false hope. The optimistic declaration &#8220;light is near&#8221; (<em>ʾôr qārôḇ mippᵉnê-ḥōšeḵ</em>) in the presence of darkness is the definition of Eliphaz&#8217;s consolations (15:11): they claim imminent relief for someone surrounded by darkness. Job refuses this inversion: the darkness he experiences is real; naming it &#8220;light&#8221; is a lie. This epistemological conflict &#8212; reality versus comfortable optimism &#8212; is one of the book&#8217;s central concerns.</p>",
    "13": "<p>&#8220;If I wait, Sheol is my home &#8212; I have made my bed in the darkness.&#8221; Job&#8217;s expectation of where hope leads: not to light (v12, the Friends&#8217; false promise) but to Sheol. <em>Im-ʾᵃqawweh šᵉʾôl bêṯî</em> (if I hope/wait, Sheol is my house) &#8212; waiting produces only Sheol as dwelling place. <em>Bᵃḥōšeḵ rāpaʿdtî yᵉṣûʿî</em> (in darkness I have spread my bed) &#8212; the bed-in-darkness is the most intimate image of dwelling: Job has not just passed through darkness but has made it his permanent resting place. The domestic language (house, bed) applied to Sheol is the extreme form of hopelessness: death has become home.</p>",
    "14": "<p>&#8220;I call out to corruption, &#8216;You are my father,&#8217; and to the worm, &#8216;My mother and my sister.&#8217;&#8221; The grotesque reversal of covenant-family language: <em>lašṣaḥaṯ qārāʾtî ʾāḇî ʾāttāh</em> (to the pit/corruption I call: you are my father) and <em>lārimmāh ʾimmi wᵉʾᵃḥōṯî</em> (to the worm: my mother and my sister). The intimate family terms (<em>ʾāḇ</em>, father; <em>ʾēm</em>, mother; <em>ʾāḥôṯ</em>, sister) applied to decay and worms is the ultimate estrangement: the human relational network that was Job&#8217;s identity (1:1&#8211;5) has been replaced by the relational network of dissolution.</p>",
    "15": "<p>&#8220;Where then is my hope? Who can see hope for me?&#8221; <em>Wᵉʾayyēh ʾēpô tiqwāṯî</em> (and where then is my hope?) &#8212; <em>tiqwāh</em> (hope) is one of the book&#8217;s central terms. In ch14, Job explored hope under the image of the tree that might sprout (14:7&#8211;9) and concluded that, unlike the tree, human death offers no revival. Here the question is even starker: hope itself has no location. The question <em>ûtiqwāṯî mî yᵉšûrennāh</em> (who can see my hope?) suggests hope has become invisible &#8212; not just deferred but undetectable. The rhetorical despair here sets the stage for ch19&#8217;s unexpected eruption of hope in the <em>gōʾēl</em> passage.</p>",
    "16": "<p>&#8220;Will it descend with me to the gates of Sheol? Together we shall go down into the dust.&#8221; <em>Baḏḏê šᵉʾôl tēreḏnāh</em> (will they descend to the bars/gates of Sheol?) &#8212; the bars (<em>badîm</em>) or gates of Sheol are the portals of the underworld from which no return is possible (Isa 38:10: Hezekiah&#8217;s lament; Ps 9:13). Hope descends into the dust alongside Job &#8212; hope itself dies. This is the nadir of the speech and among the lowest points of the book before the <em>gōʾēl</em> passage of 19:25&#8211;27 reverses direction. The structural movement of the book requires this depth: the resolution that comes must be proportionate to the despair expressed.</p>"
  },
  "18": {
    "1": "<p>Bildad delivers his second speech (his first was in ch8). Like Eliphaz&#8217;s second speech, it is more aggressive than the first. Where Bildad&#8217;s first speech appealed to natural and generational cycles (8:8&#8211;19), his second speech constructs an elaborate fate-of-the-wicked poem (vv5&#8211;21). It is the most sustained and vivid poetic treatment of the wicked man&#8217;s doom in the dialogue section, drawing on a range of ANE literary conventions: hunting-trap imagery, lamp-extinction symbolism, death-personification, and name-erasure curses.</p>",
    "2": "<p>&#8220;How long before you stop talking? Think first, and then we will have our say.&#8221; <em>ʿaḏ-ʾānāh tiśîmûn qinṣê-millîn</em> (how long will you set snares of words?) &#8212; the plural <em>tiśîmûn</em> suggests Bildad may be addressing Job and his supporters, or addressing the company collectively. <em>Tāḇînû</em> (understand/discern first) before speaking &#8212; the wisdom-pedagogy principle inverted: Bildad accuses Job of speaking without prior understanding. The two-step (<em>ûḇaʿᵃḵēn nᵉḏabbēr</em>, then we will speak) implies a proper order: comprehension before articulation. Bildad is positioning his own speech as properly understood, in contrast to Job&#8217;s reflexive protest.</p>",
    "3": "<p>&#8220;Why do you regard us as animals? Why are we worthless in your eyes?&#8221; Bildad&#8217;s personal pique: Job&#8217;s dismissal of the Friends as animals (<em>nibᵉḏamennû</em>, as animals) and as defiled/worthless (<em>ṭāmîm bᵉʿênêḵem</em>). Job has in fact compared himself favorably to the Friends&#8217; wisdom (12:7&#8211;9: the animals and birds know more than the Friends know), which Bildad apparently took personally. The breakdown of the discourse community &#8212; from respectful debate to mutual contempt &#8212; is tracked in these accusation-counter-accusation exchanges that mark the second cycle.</p>",
    "4": "<p>&#8220;You who tear yourself apart in your rage &#8212; will the earth be forsaken on your account? Will the rock be moved from its place for you?&#8221; <em>Ṭōrēp napšô bᵉʾappô</em> (you who tear your own soul in your anger) &#8212; Bildad turns Job&#8217;s warrior-God imagery back on Job himself: the tearing is self-inflicted, the product of Job&#8217;s own rage. The rhetorical questions &#8212; will the earth be abandoned on your account? will the rock be moved for you? &#8212; mockingly suggest that Job believes the entire natural order should accommodate his complaints. The rock (<em>ṣûr</em>) as foundational stability recalls the creation theology in which God set the foundations immovably (38:4&#8211;7).</p>",
    "5": "<p>&#8220;Yes, the light of the wicked is extinguished; the flame of his fire gives no light.&#8221; The lamp-extinction motif begins the fate-of-the-wicked poem. <em>Nēr rᵉšāʿîm yidʿāḵ</em> (the lamp of the wicked is extinguished) &#8212; in the ancient world, the lamp (<em>nēr</em>) was both a practical light source and a symbol of life, family continuity, and the presence of the divine. To have one&#8217;s lamp extinguished was to have one&#8217;s life and line ended (Prov 13:9: &#8220;the lamp of the wicked will be extinguished&#8221;; 20:20; 24:20). The flame that gives no light (<em>šabaḥ ʾēšô nōgāh</em>) &#8212; even what appears to burn is without illuminating effect.</p>",
    "6": "<p>&#8220;The light in his tent grows dark, and the lamp over him is extinguished.&#8221; The movement from communal lamp (v5) to personal/domestic lamp (v6): <em>ʾôr ḥāšaḵ bᵉʾōhᵃlô</em> (the light darkens in his tent) and <em>wᵉnērô ʿālāyw yiddaʿᵃḵ</em> (his lamp above him is extinguished). The tent (<em>ʾōhel</em>) and the lamp-above-him are domestic images. In patriarchal and nomadic contexts, the well-lit tent was a sign of hospitality, prosperity, and protection; the dark tent is its opposite &#8212; abandonment and curse. The imagery applies to Job&#8217;s situation ironically: Job&#8217;s household has already been darkened (1:18&#8211;19).</p>",
    "7": "<p>&#8220;His powerful stride is shortened, and his own schemes bring him down.&#8221; <em>Yiṣṣᵃrû ṣᵃʿᵃdê ʾônô</em> (the steps of his strength are shortened) &#8212; the diminishment of physical power. <em>Wᵉtašlîḵēhû ʿᵃṣāṯô</em> (his own counsel/plans throw him down) &#8212; the self-entrapment motif: the wicked man&#8217;s downfall is engineered by his own scheming. This is the boomerang principle of Proverbs (Prov 1:18&#8211;19; 26:27; Ps 7:15&#8211;16): the trap the wicked set for others catches themselves. The transition from lamp imagery to stride-shortening to self-entrapment prepares the extensive trap-and-net imagery of vv8&#8211;10.</p>",
    "8": "<p>&#8220;He is thrown into a net by his own feet, and he walks right onto a snare.&#8221; <em>Kî šullaḥ bᵉreṯeṯ bᵉraglāyw</em> (for he is sent into a net by his own feet) &#8212; the passive suggests divine agency behind the snare. The extensive trap vocabulary in vv8&#8211;10 &#8212; <em>rešeṯ</em> (net), <em>śᵉḇāḵāh</em> (snare), <em>pāḥ</em> (trap), <em>ṣāmîm</em> (snare), <em>ḥeḇel</em> (rope/cord) &#8212; is a deliberate accumulation of hunting imagery. In the ANE, hunting provided one of the primary metaphors for divine judgment (Ezek 12:13; 17:20; Jer 18:22; Hos 7:12). The multiplication of trap-types implies inescapability: however the wicked man moves, a trap awaits.</p>",
    "9": "<p>&#8220;A trap catches him by the heel; a snare holds him tight.&#8221; <em>Yōʾḥez bᵉʿāqēḇ pāḥ</em> (a trap seizes him by the heel) &#8212; the heel (<em>ʿāqēḇ</em>) as the point of vulnerability. The heel is the anatomically vulnerable site in ancient combat and is associated in the OT with Jacob/Israel (Gen 25:26: grasping the heel) and with the serpent&#8217;s attack (Gen 3:15: striking the heel). <em>Yᵃḥᵃzēq ʿālāyw ṣāmîm</em> (the snare holds him firm) &#8212; the trap&#8217;s grip is total. The hunting imagery in vv8&#8211;10 may have influenced Psalm 91:3 (&#8220;he will save you from the fowler&#8217;s snare&#8221;) as the positive counter-promise.</p>",
    "10": "<p>&#8220;A rope is buried in the ground for him, and a trap waits on his path.&#8221; <em>Ṭāmûn bāʾāreṣ ḥaḇlô</em> (his rope is hidden in the ground) &#8212; the concealed trap, the hidden danger. The trap waits on the <em>nᵉṯîḇāh</em> (path, way) &#8212; the path-language ties the hunting imagery to the wisdom literature&#8217;s two-ways theology: the wicked man&#8217;s very path is mined with traps. Compare Ps 1:6 (&#8220;the way of the wicked will perish&#8221;) &#8212; not through external intervention alone but through the structural entrapment that the wicked way entails. The &#8220;way&#8221; that leads to death is a trapped way.</p>",
    "11": "<p>&#8220;Terrors frighten him on every side and push him forward at every step.&#8221; <em>Sābîḇ bittᵃhûhû bālāhôṯ</em> (terrors frighten him on every side) &#8212; the plural <em>bālāhôṯ</em> (terrors, sudden destructions) are personified forces surrounding the wicked man. <em>Wᵉhēpîṣuhû lᵉraglāyw</em> (they push/scatter him at his feet) &#8212; the terror-forces drive him forward, not allowing him to stand. The image is of a panicked animal driven by beaters on all sides &#8212; no matter which direction the wicked man moves, terror drives him further into the trap. The &#8220;king of terrors&#8221; (v14) is the destination toward which these surrounding terrors drive him.</p>",
    "12": "<p>&#8220;His strength is starved, and disaster stands ready at his side.&#8221; <em>Yᵉhî-rāʿēb ʾônô</em> (his strength is hungry/starved) &#8212; the strength (<em>ʾôn</em>) that made his stride powerful (v7) is now famished. <em>Wᵉʾêḏ nāḵôn lᵉṣalʿô</em> (and disaster stands ready at his side) &#8212; <em>ʾêḏ</em> (disaster, calamity) as a quasi-personified attendant: not a random misfortune but a constant companion ready to strike. The image of disaster as a constant companion at the side contrasts with Psalm 23:6 (&#8220;goodness and steadfast love will follow me all my days&#8221;) &#8212; for the wicked, the constant follower is <em>ʾêḏ</em> rather than <em>ḥeseḏ</em>.</p>",
    "13": "<p>&#8220;His skin is eaten away piece by piece; the firstborn of death devours his body.&#8221; <em>Yōʾkal baḏḏê ʿôrô</em> (it eats his skin piece by piece) &#8212; a disease that consumes the body from outside. <em>Yōʾkal baḏḏāyw bᵉḵôr māweṯ</em> (the firstborn of death devours his limbs) &#8212; <em>bᵉḵôr māweṯ</em> (firstborn of death) is unique in the OT: a metaphorical or mythological figure, the most powerful of death&#8217;s offspring. In Canaanite mythology, Mot (Death) was a deity with a household and realm; his &#8220;firstborn&#8221; would be his most powerful offspring. The verse applies to Job&#8217;s condition exactly &#8212; his skin has been consumed (2:7: &#8220;painful sores from the soles of his feet to the crown of his head&#8221;).</p>",
    "14": "<p>&#8220;His confidence is ripped away from his home, and he is brought before the king of terrors.&#8221; <em>Yinnāteq mēʾōhᵃlô miḇṭaḥô</em> (his confidence is torn/ripped from his tent) &#8212; <em>miḇṭāḥ</em> (confidence, security, what one trusts in) is what Eliphaz said was available to the righteous (4:6) but the wicked lose. <em>Wᵉtaṣʿidēhû lᵉmelek ballāhôṯ</em> (and he is marched before the king of terrors) &#8212; <em>melek ballāhôṯ</em> (king of terrors) is the most vivid death-personification in the book. In Ugaritic texts, Mot is a royal figure who rules the underworld. The formal march (<em>tṣʿd</em>, to cause to march/step) before this king is a court procession &#8212; the wicked man is brought as a condemned prisoner before death&#8217;s throne. Revelation 1:18 responds: &#8220;I hold the keys of Death and Hades.&#8221;</p>",
    "15": "<p>&#8220;Something alien has moved into his tent; brimstone is scattered over his home.&#8221; <em>Tiškon bᵉʾōhᵃlô mibbᵉlî-lô</em> (something dwells in his tent that is not his) &#8212; the tent occupied by an alien presence, the opposite of the prosperous household. <em>Wᵉzōreh ʿal-nāwêhû goprit</em> (brimstone is scattered over his dwelling) &#8212; brimstone (<em>goprit</em>) is the material of divine judgment: the destruction of Sodom and Gomorrah (Gen 19:24), the judgment oracles of the prophets (Isa 34:9; Ezek 38:22; Ps 11:6). The scattering of brimstone over the dwelling makes the site permanently consecrated to destruction &#8212; nothing will grow there again (Deut 29:23).</p>",
    "16": "<p>&#8220;His roots dry up below; his branches wither above.&#8221; The arboreal metaphor for human life and posterity: <em>mittaḥaṯ šāreśāyw yiḇāšû</em> (his roots dry up below) and <em>ûmimmaʿal yimmāl qᵉṣîrô</em> (his branches/harvest wither above). Job used the same tree image to express hope (14:7&#8211;9: &#8220;there is hope for a tree &#8212; if it is cut down it will sprout again&#8221;). Bildad denies that hope for the wicked: the roots fail before the branches wither, meaning there is no possibility of recovery. The comprehensive destruction &#8212; roots and branches &#8212; eliminates both past (roots) and future (branches) simultaneously.</p>",
    "17": "<p>&#8220;His memory vanishes from the land; he has no name in the open places.&#8221; <em>Ziḵrô ʾāḇaḏ min-ʾāreṣ</em> (his memory perishes from the earth) and <em>wᵉlōʾ-šēm lô ʿal-pᵉnê-ḥûṣ</em> (no name for him in the open/outside) &#8212; the erasure of name and memory is the ultimate death in the ancient world, where the name&#8217;s survival constituted a form of immortality. The name that persisted in the public places (<em>ḥûṣ</em> = streets, public squares) was the sign of a life that had mattered. Proverbs 10:7 and 22:1 make the name&#8217;s persistence a mark of the righteous. To have no name in the open places is the final deletion from communal memory.</p>",
    "18": "<p>&#8220;He is driven from light into darkness and banished from the world.&#8221; <em>Yihdᵃpēhû miʾôr ʾel-ḥōšeḵ</em> (he is thrust from light into darkness) &#8212; the light-darkness contrast that runs through the book reaches its destination here: the wicked man arrives at the permanent darkness that was his trajectory from 15:22. <em>Ûmittēḇēl yᵉniddūhû</em> (and from the world he is banished) &#8212; <em>tēḇēl</em> (world, inhabited earth) is the sphere of human community and divine ordering. Banishment from the <em>tēḇēl</em> is cosmic exile &#8212; not just social death or personal death but exclusion from the ordered world itself. Compare Cain&#8217;s banishment (Gen 4:12&#8211;14) as the prototype of this condition.</p>",
    "19": "<p>&#8220;He has no offspring or descendants among his people, and no survivor where he once lived.&#8221; <em>Lōʾ-nîn lô wᵉlōʾ-neḵeḏ bᵉʿammô</em> (no son and no grandson among his people) &#8212; the genealogical erasure following the name-erasure of v17. <em>Wᵉʾên śārîḏ bimgûrāyw</em> (no survivor in his dwelling places) &#8212; the word <em>śārîḏ</em> (survivor, refugee) was used of those who survived divine judgment (Jer 42:17; 44:14; Joel 2:32). The complete absence of any survivor from the wicked man&#8217;s household is the absolute form of the divine judgment that leaves nothing remaining. Bildad&#8217;s description of total annihilation is implicitly applied to Job: no children (1:18&#8211;19), no household (1:15&#8211;17).</p>",
    "20": "<p>&#8220;Those who come after him are horrified by his fate; those who went before him are seized with dread.&#8221; <em>ʿal-yômô nāšammû ʾaḥᵃrōnîm</em> (at his day those who come after are horrified) and <em>wᵉqaḏmōnîm ʾāḥᵃzû śāʿar</em> (and those who went before are seized with dread) &#8212; the judgment functions as a warning to all generations: past and future witnesses are both appalled. This universalizing gesture frames the fate-of-the-wicked poem as an instructional text for all observers. The pedagogical function of observed judgment is a key mechanism of wisdom ethics (Prov 24:30&#8211;34; Ps 37:35&#8211;36).</p>",
    "21": "<p>Bildad&#8217;s summary verdict closes the poem with the explicit category: <em>lōʾ-yāḏaʿ ʾēl</em> (the one who does not know God). In the wisdom and prophetic traditions, &#8220;not knowing God&#8221; is the fundamental orientation that produces all the downstream consequences the poem has described (Jer 2:8; 4:22; 9:3,6; Hos 4:1,6). Not-knowing is both cognitive (lacking accurate understanding of who God is) and relational (refusing the covenant-relationship with God). Bildad&#8217;s implicit accusation: Job&#8217;s conduct reveals him to be one who does not know God &#8212; the exact opposite of the book&#8217;s opening claim (1:1: &#8220;he feared God&#8221;).</p>"
  }
}

def main():
    existing = load_comm('mkt-context', 'job')
